svg.script:

document.addEventListener("DOMContentLoaded", function() {
    // Luister naar berichten van de hoofdwebsite
    window.addEventListener("message", function(event) {
        // Optioneel: Voeg hier een controle toe voor event.origin als je specifieke domeinen wilt white-listen

        const data = event.data;

        if (data.action === "write") {
            try {
                localStorage.setItem(data.key, JSON.stringify(data.value));
                event.source.postMessage({ status: "success", key: data.key }, event.origin);
            } catch (e) {
                event.source.postMessage({ status: "error", message: e.message }, event.origin);
            }
        }

        if (data.action === "read") {
            try {
                const value = JSON.parse(localStorage.getItem(data.key));
                event.source.postMessage({ status: "read_result", key: data.key, value: value }, event.origin);
            } catch (e) {
                event.source.postMessage({ status: "error", message: e.message }, event.origin);
            }
        }
    });

    // Meld aan de parent dat de bridge klaar is voor gebruik
    if (window.parent) {
        window.parent.postMessage({ status: "bridge_ready" }, "*");
    }
});
